export async function POST(req: NextRequest) {
  try {
    const formData = await req.formData();
    const messageText = formData.get('text') as string;
    const imageData = formData.get('image') as string | null;
    
    let messages: any[];
    
    if (imageData) {
      // Validate image format
      if (!imageData.startsWith('data:image/') && !imageData.startsWith('http')) {
        return NextResponse.json(
          { error: 'Formato de imagen no válido. Asegúrate de subir una imagen válida (JPEG, PNG, etc.)' },
          { status: 400 }
        );
      }
      
      messages = [
        { role: 'system', content: SYSTEM_PROMPT },
        {
          role: 'user',
          content: [
            { type: 'text', text: messageText || 'Analiza esta imagen y dime qué contiene, especialmente si es un documento legal.' },
            { type: 'image_url', image_url: { url: imageData } }
          ]
        }
      ];
    } else {
      const parsedMessages = JSON.parse(formData.get('messages') as string || '[]');
      messages = [
        { role: 'system', content: SYSTEM_PROMPT },
        ...parsedMessages
      ];
    }

    const modelToUse = imageData ? 'openai/gpt-4o' : 'deepseek/deepseek-chat';

    let requestBody: any = {
      model: modelToUse,
      messages: messages,
      temperature: 0.7,
      max_tokens: 2000
    };

    if (!imageData) {
      requestBody.tools = TOOLS_DEFINITION;
      requestBody.tool_choice = "auto";
    }

    const response = await fetch(OPENROUTER_API_URL, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${OPENROUTER_API_KEY}`,
        'Content-Type': 'application/json',
        'HTTP-Referer': 'http://localhost:3456',
        'X-Title': 'LexMex - Asesor Legal'
      },
      body: JSON.stringify(requestBody)
    });

    if (!response.ok) {
      const errorData = await response.json();
      console.error('OpenRouter API error:', errorData);
      
      if (errorData.error?.message?.includes('image')) {
        return NextResponse.json(
          { error: 'El modelo actual no puede procesar imágenes. Puedes intentar con documentos PDF o describir el contenido.' },
          { status: 400 }
        );
      }
      
      return NextResponse.json(
        { error: errorData.error?.message || 'Error al comunicarse con la API' },
        { status: response.status }
      );
    }

    const data = await response.json();
    
    if (!imageData && data.choices?.[0]?.message?.tool_calls) {
      const toolCalls = data.choices[0].message.tool_calls;
      const toolResults: any[] = [];
      
      for (const toolCall of toolCalls) {
        const args = JSON.parse(toolCall.function.arguments);
        const result = handleToolCall(toolCall.function.name, args);
        toolResults.push({
          tool_call_id: toolCall.id,
          role: "tool",
          content: JSON.stringify(result)
        });
      }
      
      messages.push(data.choices[0].message);
      messages.push(...toolResults);
      
      const secondResponse = await fetch(OPENROUTER_API_URL, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${OPENROUTER_API_KEY}`,
          'Content-Type': 'application/json',
          'HTTP-Referer': 'http://localhost:3456',
          'X-Title': 'LexMex - Asesor Legal'
        },
        body: JSON.stringify({
          model: modelToUse,
          messages: messages,
          temperature: 0.7,
          max_tokens: 2000
        })
      });
      
      const secondData = await secondResponse.json();
      
      return NextResponse.json({
        message: secondData.choices?.[0]?.message?.content || 'No se recibió respuesta',
        usage: secondData.usage
      });
    }
    
    return NextResponse.json({
      message: data.choices?.[0]?.message?.content || 'No se recibió respuesta',
      usage: data.usage
    });

  } catch (error) {
    console.error('Error en el chat:', error);
    return NextResponse.json(
      { error: 'Error interno del servidor' },
      { status: 500 }
    );
  }
}
